// Process: SC_THREAD run
// Static sensitivity: 

void mc_testbench::run() {
   testbench::enable_idle_sync_mode = false;
   testbench::idle_sync_stable_cycles = 1;
   testbench::A_ignore = false;
   testbench::A_skip = false;
   testbench::A_skip_quiet = false;
   testbench::A_skip_once = false;
   testbench::A_skip_noerr = false;
   testbench::A_array_comp_first = -1;
   testbench::A_array_comp_last = -1;
   testbench::A_wait_ctrl.clear();
   A_capture_count = 0;
   A_iteration_count = 0;
   testbench::B_ignore = false;
   testbench::B_skip = false;
   testbench::B_skip_quiet = false;
   testbench::B_skip_once = false;
   testbench::B_skip_noerr = false;
   testbench::B_array_comp_first = -1;
   testbench::B_array_comp_last = -1;
   testbench::B_wait_ctrl.clear();
   B_capture_count = 0;
   B_iteration_count = 0;
   testbench::C_ignore = false;
   testbench::C_skip = false;
   testbench::C_skip_quiet = false;
   testbench::C_skip_once = false;
   testbench::C_skip_noerr = false;
   testbench::C_array_comp_first = -1;
   testbench::C_array_comp_last = -1;
   testbench::C_use_mask = false;
   testbench::C_output_mask = ~0;
   testbench::C_wait_ctrl.clear();
   C_capture_count = 0;
   C_iteration_count = 0;
   testbench testbench_inst(sc_argc(), sc_argv());
   main_exit_code = testbench_inst.main();
   cout<<"Info: Execution of user-supplied C++ testbench 'main()' has completed with exit code = " << main_exit_code << endl;
   cout<<endl;
   cout<<"Info: Collecting data completed"<<endl;
   cout<<"   captured "<<A_capture_count<<" values of A"<<endl;
   cout<<"   captured "<<B_capture_count<<" values of B"<<endl;
   cout<<"   captured "<<C_capture_count<<" values of C"<<endl;
   testbench_ended = true;
   testbench_end_event.notify(SC_ZERO_TIME);
}
